import{_ as t,o as e,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"안티 요요 시스템 (Anti Yo-Yo System)","description":"","frontmatter":{},"headers":[],"relativePath":"ko/advanced/anti-yoyo.md","filePath":"ko/advanced/anti-yoyo.md"}'),l={name:"ko/advanced/anti-yoyo.md"};function s(n,o,c,r,p,d){return e(),a("div",null,[...o[0]||(o[0]=[i('<h1 id="안티-요요-시스템-anti-yo-yo-system" tabindex="-1"><i class="ph ph-arrows-clockwise"></i> 안티 요요 시스템 (Anti Yo-Yo System) <a class="header-anchor" href="#안티-요요-시스템-anti-yo-yo-system" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-arrows-clockwise&quot;&gt;&lt;/i&gt; 안티 요요 시스템 (Anti Yo-Yo System)&quot;">​</a></h1><p>동적 스케일링 시스템의 가장 성가신 문제 중 하나는 <strong>요요 현상(Yo-Yo Effect)</strong>(또는 품질 탁구)입니다.</p><h2 id="핵심-문제" tabindex="-1"><i class="ph ph-warning-circle"></i> 핵심 문제 <a class="header-anchor" href="#핵심-문제" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-warning-circle&quot;&gt;&lt;/i&gt; 핵심 문제&quot;">​</a></h2><p>지능형 제어가 없으면 시스템은 무한 루프에 빠집니다:</p><ol><li>무거운 씬으로 인해 FPS가 떨어집니다.</li><li>플러그인은 그래픽 품질을 줄입니다(예: 해상도 삭감).</li><li>부하가 감소하고 FPS가 기준선 이상으로 상승합니다.</li><li>플러그인은 성능 여유(Performance Headroom)가 있다고 추론하고 그래픽 품질을 최대로 복원합니다.</li><li>FPS가 다시 떨어집니다. 이 주기가 반복됩니다.</li></ol><p>결과적으로 플레이어는 지속적인 품질 깜박임(Quality flickering)을 겪게 됩니다. 그림자가 끊임없이 나타났다가 사라지고, 이미지가 1초마다 흐릿해졌다가 선명해지기를 반복합니다.</p><h2 id="webap-솔루션-페널티-록아웃-penalty-lockout" tabindex="-1"><i class="ph ph-shield-check"></i> WebAP 솔루션: 페널티 록아웃 (Penalty Lockout) <a class="header-anchor" href="#webap-솔루션-페널티-록아웃-penalty-lockout" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-shield-check&quot;&gt;&lt;/i&gt; WebAP 솔루션: 페널티 록아웃 (Penalty Lockout)&quot;">​</a></h2><p>플러그인 설정의 두 가지 매개변수를 기반으로 구축된 페널티 록아웃의 개념을 구현하여 이 문제를 완전히 근절했습니다.</p><p>플러그인이 그래픽 품질을 <em>높이면</em> 숨겨진 타이머인 <strong>Detection Window</strong>(예: 15초)가 시작됩니다. 이 기간 동안 Indexer는 프레임 안정성을 면밀히 모니터링합니다.</p><p>이 기간 동안 FPS가 갑자기 떨어지면 시스템은 확실한 결론을 도출합니다: <em>«이전 그래픽 향상은 실수였습니다. 기기가 장기적으로 이 수준을 유지할 수 없습니다.»</em></p><p><strong>페널티가 적용됩니다:</strong></p><ol><li>플러그인은 즉시 품질을 다시 낮춥니다.</li><li>엄격한 <strong>Penalty Lockout Duration</strong>(예: 60초)이 적용됩니다.</li><li>이 1분 동안 플러그인이 그래픽 품질 향상을 시도하는 것은 <strong>단호하게 금지</strong>됩니다. FPS가 급등하고 프로세서가 유휴 상태가 되더라도 마찬가지입니다.</li></ol><div class="tip custom-block"><p class="custom-block-title">세션 잠금 (Session Lock)</p><p>게임 역학에 부하 급증이 파도처럼 발생하고 첫 번째 하락 후 품질이 다시 회복되지 않기를 선호하는 경우 <strong>Penalty Lockout Duration</strong> 필드에 엄청난 값(예: 10분은 <code>600</code>, 1시간은 <code>3600</code>)을 지정하기만 하면 됩니다. 이는 게임 세션이 끝날 때까지 일관된 낮은 수준으로 그래픽을 효과적으로 고정합니다.</p></div><div class="info custom-block"><p class="custom-block-title">유창성(Fluency) 우선순위</p><p>페널티는 오로지 렌더링을 향상시키려는 시도만 차단합니다. 플레이어가 훨씬 더 무거운 씬에 진입하고 FPS가 임계 임계값 아래로 떨어지면 플러그인은 여전히 ​​응급으로 품질을 낮출 수 있습니다. 시스템은 항상 시각 효과보다 게임 플레이 유창성을 우선시합니다.</p></div>',14)])])}const m=t(l,[["render",s]]);export{u as __pageData,m as default};
